import { useState } from "react";
import { MdArrowBack } from "react-icons/md";
import { FaEnvelope, FaKey } from "react-icons/fa"; // Import key icon for OTP
import { useNavigate } from "react-router-dom";
import "./forgotpassword.css";
import axios from "axios";

const ForgotPassword = () => {
  const [email, setEmail] = useState("");
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
  const [step, setStep] = useState("email"); // Step control: "email" or "otp"
  const [otp, setOtp] = useState("");
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleEmailSubmit = async (e) => {
    e.preventDefault();
    if (!email) {
      setError("Email is required!");
      setSuccess("");
      return;
    }

    if (!/\S+@\S+\.\S+/.test(email)) {
      setError("Enter a valid email address!");
      setSuccess("");
      return;
    }

    setLoading(true); // Set loading state
    try {
      const response = await axios.post("http://localhost:5000/api/auth/forgot-password", { email });

      if (response.data.exists) {
        setSuccess("OTP sent! Check your email.");
        setStep("otp"); // Move to OTP step
        setError("");
      } else {
        setError("Not a valid email. Enter a registered college email.");
        setSuccess("");
      }
    } catch (error) {
      setError(error.response?.data?.message || "Request failed❌");
      setSuccess("");
    } finally {
      setLoading(false); // Reset loading state
    }
  };

  const handleOtpSubmit = async (e) => {
    e.preventDefault();
    if (!otp) {
      setError("Enter OTP!");
      return;
    }

    setLoading(true);
    try {
      const response = await axios.post("http://localhost:5000/api/auth/verify-otp", {
        email,
        otp,
      });

      if (response.data.verified) {
        navigate("/reset-password"); // Redirect to Reset Password page
      } else {
        setError("Invalid OTP. Try again.");
      }
    } catch (error) {
      setError(error.response?.data?.message || "OTP verification failed!");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="forgot-password-container">
      <div className="back-to-login" onClick={() => navigate("/")}>
        <MdArrowBack />
      </div>
      <img src="/assets/ODCSE Logo.png" alt="Logo" className="logo" />

      {step === "email" ? (
        <>
          <h2 className="forgot-password-title">Forgot Password</h2>
          <p className="instruction-text">Enter a valid email address to reset your password.</p>

          <form onSubmit={handleEmailSubmit} className="forgot-password-form">
            <div className="input-group">
              <FaEnvelope className="icon" />
              <input
                type="email"
                placeholder="College Mail ID"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
              />
            </div>

            <button type="submit" className="reset-button" disabled={loading}>
              {loading ? "Sending OTP..." : "Reset Password"}
            </button>

            <div className="message-container">
              {error && <p className="error-message">{error}</p>}
              {success && <p className="success-message">{success}</p>}
            </div>
          </form>
        </>
      ) : (
        <>
          <h2 className="forgot-password-title">Enter OTP</h2>
          <p className="instruction-text">A 6-digit OTP has been sent to your email.</p>

          <form onSubmit={handleOtpSubmit} className="forgot-password-form">
            <div className="input-group">
              <FaKey className="icon" />
              <input
                type="text"
                placeholder="Enter OTP"
                value={otp}
                onChange={(e) => setOtp(e.target.value)}
                maxLength="6"
              />
            </div>

            <button type="submit" className="reset-button" disabled={loading}>
              {loading ? "Verifying..." : "Verify OTP"}
            </button>

            <div className="message-container">
              {error && <p className="error-message">{error}</p>}
            </div>
          </form>
        </>
      )}
    </div>
  );
};

export default ForgotPassword;
